   173→      }
   174→
   175→      if (response.status === 403 && data.requiresConsent) {
   176→        return 'needs-consent';
   177→      }
   178→
   179→      if (response.status === 404) {
   180→        return 'no-profile';
   181→      }
   182→
   183→      throw new Error(data.error || 'Failed to fetch profile');
   184→    } catch (err) {
   185→      throw err;
