                  </span>
                </div>
              ) : null}
            </div>
          )}
        </div>
      </header>

      <div className="p-4 sm:p-6 md:p-8 pt-6 sm:pt-8">
        <div className="max-w-4xl mx-auto">
          {renderContent()}
        </div>
      </div>

      {/* Parent-Professor Chat Modal (Issue #63) */}
      {chatMaestro && (
        <ParentProfessorChat
          maestroId={chatMaestro.id}
