    10→import type { UsageStats, ChartData, TimeSeriesPoint } from '@/lib/telemetry/types';
    11→
    12→export async function GET() {
    13→  try {
    14→    const cookieStore = await cookies();
    15→    const userId = cookieStore.get('convergio-user-id')?.value;
    16→
    17→    if (!userId) {
    18→      return NextResponse.json({ error: 'No user' }, { status: 401 });
    19→    }
    20→
    21→    const now = new Date();
    22→    const todayStart = new Date(now);
    23→    todayStart.setHours(0, 0, 0, 0);
    24→
    25→    const weekStart = new Date(now);
    26→    weekStart.setDate(weekStart.getDate() - 7);
    27→    weekStart.setHours(0, 0, 0, 0);
    28→
    29→    // Fetch all data in parallel
    30→    const [
    31→      todayEvents,
    32→      weekEvents,
    33→      sessions,
    34→      studySessions,
    35→    ] = await Promise.all([
    36→      // Today's telemetry events
    37→      prisma.telemetryEvent.findMany({
    38→        where: {
    39→          userId,
    40→          timestamp: { gte: todayStart },
    41→        },
    42→      }),
    43→      // Week's telemetry events
    44→      prisma.telemetryEvent.findMany({
    45→        where: {
    46→          userId,
    47→          timestamp: { gte: weekStart },
    48→        },
    49→        orderBy: { timestamp: 'asc' },
    50→      }),
    51→      // All sessions from telemetry (session_started events)
    52→      prisma.telemetryEvent.findMany({
    53→        where: {
    54→          userId,
    55→          category: 'navigation',
    56→          action: 'session_started',
    57→          timestamp: { gte: weekStart },
    58→        },
    59→      }),
    60→      // Study sessions from progress
    61→      prisma.studySession.findMany({
    62→        where: {
    63→          userId,
    64→          startedAt: { gte: weekStart },
    65→        },
    66→        orderBy: { startedAt: 'asc' },
    67→      }),
    68→    ]);
    69→
    70→    // Calculate today's stats
    71→    const todaySessions = todayEvents.filter(
    72→      (e) => e.category === 'navigation' && e.action === 'session_started'
    73→    ).length;
    74→
    75→    const todayStudyMinutes = studySessions
    76→      .filter((s) => s.startedAt >= todayStart)
