     3→// ============================================================================
     4→// TELEMETRY DASHBOARD
     5→// Usage analytics visualization for settings tab
     6→// ============================================================================
     7→
     8→import { useEffect, useState } from 'react';
     9→import { motion } from 'framer-motion';
    10→import {
    11→  BarChart3,
    12→  TrendingUp,
    13→  TrendingDown,
    14→  Minus,
    15→  Clock,
    16→  MessageCircle,
    17→  BookOpen,
    18→  Users,
