    21→} from 'lucide-react';
    22→import { cn } from '@/lib/utils';
    23→import { Card, CardContent, CardHeader, CardTitle, CardDescription } from '@/components/ui/card';
    24→import { Button } from '@/components/ui/button';
    25→import { useTelemetryStore } from '@/lib/telemetry/telemetry-store';
    26→import type { ChartData } from '@/lib/telemetry/types';
    27→
    28→// ============================================================================
    29→// MINI CHART COMPONENT
    30→// ============================================================================
    31→
    32→interface MiniBarChartProps {
    33→  data: ChartData[];
    34→  height?: number;
    35→}
    36→
    37→function MiniBarChart({ data, height = 80 }: MiniBarChartProps) {
    38→  if (!data.length || !data[0]?.data.length) {
    39→    return (
    40→      <div
    41→        className="flex items-center justify-center text-slate-400 text-sm"
    42→        style={{ height }}
    43→      >
    44→        Nessun dato disponibile
    45→      </div>
    46→    );
    47→  }
    48→
    49→  const primaryData = data[0].data;
    50→  const maxValue = Math.max(...primaryData.map((d) => d.value), 1);
    51→  const days = ['Dom', 'Lun', 'Mar', 'Mer', 'Gio', 'Ven', 'Sab'];
    52→
    53→  return (
    54→    <div className="flex items-end justify-between gap-1" style={{ height }}>
    55→      {primaryData.map((point, index) => {
    56→        const barHeight = (point.value / maxValue) * (height - 20);
    57→        const dayLabel = days[new Date(point.timestamp).getDay()];
    58→
    59→        return (
    60→          <div key={index} className="flex flex-col items-center flex-1">
    61→            <motion.div
    62→              initial={{ height: 0 }}
    63→              animate={{ height: barHeight }}
    64→              transition={{ duration: 0.5, delay: index * 0.05 }}
    65→              className="w-full rounded-t"
    66→              style={{ backgroundColor: data[0].color }}
    67→              title={`${point.value} minuti`}
    68→            />
    69→            <span className="text-xs text-slate-500 mt-1">{dayLabel}</span>
    70→          </div>
    71→        );
    72→      })}
    73→    </div>
    74→  );
    75→}
    76→
    77→// ============================================================================
    78→// STAT CARD COMPONENT
    79→// ============================================================================
    80→
    81→interface StatCardProps {
    82→  title: string;
    83→  value: string | number;
    84→  subtitle?: string;
    85→  icon: React.ReactNode;
    86→  trend?: 'up' | 'down' | 'stable';
    87→  className?: string;
    88→}
    89→
    90→function StatCard({ title, value, subtitle, icon, trend, className }: StatCardProps) {
    91→  const TrendIcon = trend === 'up' ? TrendingUp : trend === 'down' ? TrendingDown : Minus;
    92→
    93→  return (
    94→    <Card className={cn('overflow-hidden', className)}>
    95→      <CardContent className="p-4">
    96→        <div className="flex items-center justify-between mb-2">
    97→          <div className="p-2 rounded-lg bg-slate-100 dark:bg-slate-800">
    98→            {icon}
    99→          </div>
   100→          {trend && (
   101→            <TrendIcon
   102→              className={cn(
   103→                'w-4 h-4',
   104→                trend === 'up' && 'text-emerald-500',
   105→                trend === 'down' && 'text-red-500',
   106→                trend === 'stable' && 'text-slate-400'
   107→              )}
   108→            />
   109→          )}
   110→        </div>
   111→        <div className="text-2xl font-bold text-slate-900 dark:text-white">
   112→          {value}
   113→        </div>
   114→        <div className="text-sm text-slate-500">{title}</div>
   115→        {subtitle && (
   116→          <div className="text-xs text-slate-400 mt-1">{subtitle}</div>
   117→        )}
   118→      </CardContent>
   119→    </Card>
   120→  );
   121→}
   122→
   123→// ============================================================================
   124→// FEATURE USAGE BAR
   125→// ============================================================================
   126→
   127→interface FeatureUsageBarProps {
   128→  data: ChartData[];
   129→}
   130→
   131→function FeatureUsageBar({ data }: FeatureUsageBarProps) {
   132→  if (!data.length) {
   133→    return <div className="text-sm text-slate-400">Nessun dato</div>;
   134→  }
   135→
   136→  const total = data.reduce((sum, d) => sum + (d.data[0]?.value || 0), 0);
   137→  if (total === 0) {
   138→    return <div className="text-sm text-slate-400">Nessun utilizzo questa settimana</div>;
   139→  }
   140→
   141→  return (
   142→    <div className="space-y-2">
   143→      {data.map((feature) => {
   144→        const value = feature.data[0]?.value || 0;
   145→        const percentage = (value / total) * 100;
   146→
   147→        return (
   148→          <div key={feature.label} className="flex items-center gap-2">
   149→            <div className="w-20 text-sm text-slate-600 dark:text-slate-400 truncate">
   150→              {feature.label}
   151→            </div>
   152→            <div className="flex-1 h-4 bg-slate-100 dark:bg-slate-800 rounded-full overflow-hidden">
   153→              <motion.div
   154→                initial={{ width: 0 }}
   155→                animate={{ width: `${percentage}%` }}
   156→                transition={{ duration: 0.5 }}
   157→                className="h-full rounded-full"
   158→                style={{ backgroundColor: feature.color }}
   159→              />
   160→            </div>
   161→            <div className="w-12 text-right text-sm font-medium">
   162→              {value}
   163→            </div>
   164→          </div>
   165→        );
   166→      })}
   167→    </div>
   168→  );
   169→}
   170→
   171→// ============================================================================
   172→// MAIN DASHBOARD COMPONENT
   173→// ============================================================================
   174→
   175→interface TelemetryDashboardProps {
   176→  className?: string;
   177→}
   178→
   179→export function TelemetryDashboard({ className }: TelemetryDashboardProps) {
   180→  const { localStats, usageStats, lastFetchedAt, fetchUsageStats, config, updateConfig } = useTelemetryStore();
   181→  const [isLoading, setIsLoading] = useState(false);
   182→
   183→  // Fetch stats on mount and when refreshing
   184→  useEffect(() => {
   185→    if (!lastFetchedAt || Date.now() - lastFetchedAt.getTime() > 60000) {
   186→      fetchUsageStats();
   187→    }
   188→  }, [lastFetchedAt, fetchUsageStats]);
   189→
   190→  const handleRefresh = async () => {
   191→    setIsLoading(true);
   192→    await fetchUsageStats();
   193→    setIsLoading(false);
   194→  };
   195→
