     1→// ============================================================================
     2→// API ROUTE: Azure Cost Management
     3→// Queries Azure Cost Management API for subscription costs
     4→// Supports: Service Principal (production) OR az CLI credentials (local dev)
     5→// ============================================================================
     6→
     7→import { NextRequest, NextResponse } from 'next/server';
     8→import { execSync } from 'child_process';
     9→import { logger } from '@/lib/logger';
    10→
    11→// Default subscription for ConvergioEdu
    12→const DEFAULT_SUBSCRIPTION_ID = '8015083b-adad-42ff-922d-feaed61c5d62';
    13→
    14→interface CostByService {
    15→  serviceName: string;
    16→  cost: number;
    17→  currency: string;
    18→}
    19→
    20→interface DailyCost {
    21→  date: string;
    22→  cost: number;
    23→}
    24→
    25→interface CostSummary {
    26→  subscriptionId: string;
    27→  periodStart: string;
    28→  periodEnd: string;
    29→  totalCost: number;
    30→  currency: string;
    31→  costsByService: CostByService[];
    32→  dailyCosts: DailyCost[];
    33→  source: 'service_principal' | 'az_cli';
    34→}
    35→
    36→interface CostForecast {
    37→  subscriptionId: string;
    38→  forecastPeriodEnd: string;
    39→  estimatedTotal: number;
    40→  currency: string;
    41→  source: 'service_principal' | 'az_cli';
    42→}
    43→
    44→// Simple in-memory cache
    45→const cache = new Map<string, { timestamp: number; data: unknown }>();
    46→const CACHE_TTL = 5 * 60 * 1000; // 5 minutes
    47→
    48→function getCached<T>(key: string): T | null {
    49→  const cached = cache.get(key);
    50→  if (cached && Date.now() - cached.timestamp < CACHE_TTL) {
    51→    return cached.data as T;
    52→  }
    53→  cache.delete(key);
    54→  return null;
    55→}
    56→
    57→function setCache(key: string, data: unknown): void {
    58→  cache.set(key, { timestamp: Date.now(), data });
    59→}
    60→
    61→// ============================================================================
    62→// SERVICE PRINCIPAL AUTH (Production)
    63→// ============================================================================
    64→
    65→function hasServicePrincipalCredentials(): boolean {
    66→  return !!(
    67→    process.env.AZURE_TENANT_ID &&
    68→    process.env.AZURE_CLIENT_ID &&
    69→    process.env.AZURE_CLIENT_SECRET
    70→  );
    71→}
    72→
    73→async function getAzureToken(): Promise<string | null> {
    74→  const tenantId = process.env.AZURE_TENANT_ID;
    75→  const clientId = process.env.AZURE_CLIENT_ID;
    76→  const clientSecret = process.env.AZURE_CLIENT_SECRET;
    77→
    78→  if (!tenantId || !clientId || !clientSecret) {
    79→    return null;
    80→  }
    81→
    82→  const cachedToken = getCached<string>('azure_token');
    83→  if (cachedToken) return cachedToken;
    84→
    85→  try {
    86→    const tokenUrl = `https://login.microsoftonline.com/${tenantId}/oauth2/v2.0/token`;
    87→    const response = await fetch(tokenUrl, {
    88→      method: 'POST',
    89→      headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
    90→      body: new URLSearchParams({
    91→        grant_type: 'client_credentials',
    92→        client_id: clientId,
    93→        client_secret: clientSecret,
    94→        scope: 'https://management.azure.com/.default',
    95→      }),
    96→    });
    97→
    98→    if (!response.ok) {
    99→      logger.error('Azure token error', { response: await response.text() });
   100→      return null;
   101→    }
   102→
   103→    const data = await response.json();
   104→    setCache('azure_token', data.access_token);
   105→    return data.access_token;
   106→  } catch (error) {
   107→    logger.error('Azure token fetch error', { error: String(error) });
   108→    return null;
   109→  }
   110→}
   111→
   112→async function queryCostsWithToken(
   113→  token: string,
   114→  subscriptionId: string,
   115→  queryBody: Record<string, unknown>
   116→): Promise<Record<string, unknown> | null> {
   117→  const url = `https://management.azure.com/subscriptions/${subscriptionId}/providers/Microsoft.CostManagement/query?api-version=2023-11-01`;
   118→
   119→  try {
   120→    const response = await fetch(url, {
   121→      method: 'POST',
   122→      headers: {
   123→        Authorization: `Bearer ${token}`,
   124→        'Content-Type': 'application/json',
   125→      },
   126→      body: JSON.stringify(queryBody),
   127→    });
   128→
   129→    if (response.status === 429) {
   130→      return null;
   131→    }
   132→
   133→    if (!response.ok) {
   134→      logger.error('Azure Cost API error', { response: await response.text() });
   135→      return null;
   136→    }
   137→
   138→    return response.json();
   139→  } catch (error) {
   140→    logger.error('Azure Cost query error', { error: String(error) });
   141→    return null;
   142→  }
   143→}
   144→
   145→// ============================================================================
   146→// AZ CLI AUTH (Local Development)
   147→// ============================================================================
   148→
   149→function isAzCliAvailable(): boolean {
   150→  try {
   151→    execSync('az account show', { encoding: 'utf8', stdio: 'pipe' });
   152→    return true;
   153→  } catch {
   154→    return false;
   155→  }
   156→}
   157→
   158→function queryCostsWithAzCli(
   159→  subscriptionId: string,
   160→  queryBody: Record<string, unknown>
   161→): Record<string, unknown> | null {
   162→  const url = `https://management.azure.com/subscriptions/${subscriptionId}/providers/Microsoft.CostManagement/query?api-version=2023-11-01`;
   163→
   164→  try {
   165→    const bodyJson = JSON.stringify(queryBody).replace(/"/g, '\\"');
   166→    const cmd = `az rest --method post --url "${url}" --body "${bodyJson}" -o json`;
   167→    const result = execSync(cmd, { encoding: 'utf8', timeout: 30000 });
   168→    return JSON.parse(result);
   169→  } catch (error) {
   170→    logger.error('az CLI cost query error', { error: String(error) });
   171→    return null;
   172→  }
   173→}
   174→
   175→// ============================================================================
   176→// UNIFIED QUERY FUNCTION
   177→// ============================================================================
   178→
   179→async function queryCosts(
   180→  subscriptionId: string,
   181→  queryBody: Record<string, unknown>
   182→): Promise<{ result: Record<string, unknown> | null; source: 'service_principal' | 'az_cli' }> {
   183→  // Try service principal first (production)
   184→  if (hasServicePrincipalCredentials()) {
   185→    const token = await getAzureToken();
   186→    if (token) {
   187→      const result = await queryCostsWithToken(token, subscriptionId, queryBody);
   188→      return { result, source: 'service_principal' };
   189→    }
   190→  }
   191→
   192→  // Fallback to az CLI (local dev)
   193→  if (isAzCliAvailable()) {
   194→    const result = queryCostsWithAzCli(subscriptionId, queryBody);
   195→    return { result, source: 'az_cli' };
   196→  }
   197→
   198→  return { result: null, source: 'az_cli' };
   199→}
   200→
   201→// ============================================================================
   202→// API HANDLER
   203→// ============================================================================
   204→
   205→export async function GET(request: NextRequest) {
   206→  const subscriptionId = process.env.AZURE_SUBSCRIPTION_ID || DEFAULT_SUBSCRIPTION_ID;
   207→
   208→  // Check if any auth method is available
   209→  if (!hasServicePrincipalCredentials() && !isAzCliAvailable()) {
